import{_ as e,c as a,o as n,a as o}from"./app.722a251f.js";const f=JSON.parse('{"title":"Incremento (funcional)","description":"","frontmatter":{},"headers":[],"relativePath":"artifacts/increment.md"}'),t={name:"artifacts/increment.md"},r=o('<h1 id="incremento-funcional" tabindex="-1">Incremento (funcional) <a class="header-anchor" href="#incremento-funcional" aria-hidden="true">#</a></h1><blockquote><p>Al finalizar cada Sprint, el equipo har\xE1 entrega de un incremento de funcionalidad para el sistema. Este incremento, debe lograr asemejarse a <em>\u201Cun software funcionando\u201D</em> pudiendo ser implementado en un ambiente de producci\xF3n de manera 100% operativa.</p></blockquote><p>El incremento es la parte del producto producida en un Sprint, y tiene como caracter\xEDstica el estar completamente terminada y operativa, en condiciones de ser entregada al usuario. Idealmente se produce un <em>\u201Cincremento\u201D</em> en cada iteraci\xF3n cuando se refiere a los elementos de la Pila del Producto (funcionalidades entregables), no a trabajos internos del tipo <em>\u201Cdise\xF1o de la base de datos\u201D</em>.</p><p>No se deben considerar como Incremento a prototipos, m\xF3dulos o sub-m\xF3dulos, ni partes pendientes de pruebas o integraci\xF3n. Sin embargo, es una excepci\xF3n frecuente en el primer Sprint implicar trabajos de dise\xF1o o desarrollo de prototipos para contrastar las expectativas de la plataforma o tecnolog\xEDa que se va a emplear. Por tal motivo, se necesita tener en cuenta esta excepci\xF3n habitual.</p><p>Si el proyecto o el sistema requiere documentaci\xF3n, o procesos de validaci\xF3n y verificaci\xF3n documentados, o con niveles de independencia que implican procesos con terceros, \xE9stos tambi\xE9n tienen que estar realizados para considerar que el incremento est\xE1 <em>\u201Checho\u201D</em>.</p>',5),i=[r];function c(s,d,l,p,m,u){return n(),a("div",null,i)}const b=e(t,[["render",c]]);export{f as __pageData,b as default};
